import React, { useEffect, useState, useRef } from 'react';
import { get, post, put, remove, API_BASE_URL } from '../api';

const emptyGift = {
  name: '',
  imageUrl: '',
  isActive: true,
};

const PrizeList = () => {
  const [gifts, setGifts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [workingGift, setWorkingGift] = useState(emptyGift);
  const [editingId, setEditingId] = useState(null);
  const [showForm, setShowForm] = useState(false);
  const [actionError, setActionError] = useState(null);
  const [successMessage, setSuccessMessage] = useState(null);
  const [uploadingImage, setUploadingImage] = useState(false);
  const fileInputRef = useRef(null);

  const loadGifts = async () => {
    setLoading(true);
    setError(null);
    try {
      const response = await get('/api/admin-lists/gifts');
      setGifts(response.data);
    } catch (err) {
      console.error(err);
      setError('Unable to load gifts.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadGifts();
  }, []);

  const handleRefresh = () => {
    loadGifts();
  };

  const handleEdit = (gift) => {
    setEditingId(gift.id);
    setShowForm(true);
    setWorkingGift({
      name: gift.name || '',
      imageUrl: gift.imageUrl || '',
      isActive: gift.isActive,
    });
    setActionError(null);
    setSuccessMessage(null);
  };

  const handleCreate = () => {
    setEditingId(null);
    setWorkingGift(emptyGift);
    setShowForm(true);
    setActionError(null);
    setSuccessMessage(null);
  };

  const handleCancel = () => {
    setShowForm(false);
    setEditingId(null);
    setWorkingGift(emptyGift);
    setActionError(null);
    setSuccessMessage(null);
  };

  const handleSubmit = async () => {
    setActionError(null);
    setSuccessMessage(null);

    const trimmedName = workingGift.name.trim();
    const trimmedImageUrl = workingGift.imageUrl.trim();

    if (!trimmedName) {
      setActionError('Gift name is required.');
      return;
    }

    if (!trimmedImageUrl) {
      setActionError('Gift image is required. Please upload an image.');
      return;
    }

    try {
      const payload = {
        ...workingGift,
        name: trimmedName,
        imageUrl: trimmedImageUrl,
      };

      if (editingId) {
        await put(`/api/admin-lists/gifts/${editingId}`, payload);
        setSuccessMessage('Gift updated successfully.');
      } else {
        await post('/api/admin-lists/gifts', payload);
        setSuccessMessage('Gift created successfully.');
      }
      await loadGifts();
      setEditingId(null);
      setWorkingGift(emptyGift);
      setShowForm(false);
      if (fileInputRef.current) {
        fileInputRef.current.value = '';
      }
    } catch (err) {
      console.error(err);
      setActionError('Unable to save gift.');
    }
  };

  const handleFileUpload = async (e) => {
    const file = e.target.files?.[0];
    if (!file) {
      return;
    }

    const allowedMimes = ['image/jpeg', 'image/png', 'image/gif', 'image/webp'];
    if (!allowedMimes.includes(file.type)) {
      setActionError('Only JPEG, PNG, GIF, and WebP images are allowed.');
      return;
    }

    const maxFileSize = 5 * 1024 * 1024;
    if (file.size > maxFileSize) {
      setActionError('File size must not exceed 5MB.');
      return;
    }

    setUploadingImage(true);
    setActionError(null);
    setSuccessMessage(null);

    try {
      const formData = new FormData();
      formData.append('file', file);

      const response = await post('/api/prizelist/upload-image', formData);
      if (response?.data?.imageUrl) {
        setWorkingGift({ ...workingGift, imageUrl: response.data.imageUrl });
        setSuccessMessage('Image uploaded successfully.');
      } else {
        setActionError('Upload failed: No image URL returned.');
      }
    } catch (err) {
      console.error('Upload error:', err);
      setActionError('Unable to upload image.');
    } finally {
      setUploadingImage(false);
      if (fileInputRef.current) {
        fileInputRef.current.value = '';
      }
    }
  };

  const normalizeImageUrl = (value) => {
    if (!value) {
      return '';
    }

    try {
      const parsedUrl = new URL(value, API_BASE_URL);
      if (parsedUrl.protocol === 'http:' || parsedUrl.protocol === 'https:') {
        return parsedUrl.toString();
      }
    } catch {
      // Fallback for relative URLs
    }

    if (value.startsWith('/')) {
      return `${API_BASE_URL}${value}`;
    }

    return value;
  };

  const handleDelete = async (id) => {
    setActionError(null);
    setSuccessMessage(null);
    try {
      await remove(`/api/admin-lists/gifts/${id}`);
      setSuccessMessage('Gift deleted successfully.');
      await loadGifts();
    } catch (err) {
      console.error(err);
      setActionError('Unable to delete gift.');
    }
  };

  const tableStyle = {
    width: '100%',
    minWidth: 920,
    borderCollapse: 'collapse',
    fontSize: 14,
    color: '#1f2937',
  };

  const headerStyle = {
    background: '#f8fafc',
    borderBottom: '2px solid #cbd5e1',
    textAlign: 'left',
    padding: '12px 10px',
    fontWeight: 600,
    fontSize: 13,
    color: '#111827',
  };

  const cellStyle = {
    borderBottom: '1px solid #e5e7eb',
    padding: '10px',
    verticalAlign: 'top',
    whiteSpace: 'normal',
  };

  const buttonStyle = {
    padding: '8px 14px',
    borderRadius: 5,
    border: '1px solid #cbd5e1',
    background: '#ffffff',
    cursor: 'pointer',
  };

  const inputStyle = {
    width: '100%',
    padding: '8px 10px',
    border: '1px solid #d1d5db',
    borderRadius: 4,
    fontSize: 13,
  };

  return (
    <div>
      <div style={{ marginBottom: 14, display: 'flex', flexWrap: 'wrap', gap: 8 }}>
        <button onClick={handleRefresh} disabled={loading} style={buttonStyle}>
          Refresh
        </button>
        <button onClick={handleCreate} style={buttonStyle}>
          Add New
        </button>
      </div>
      {successMessage && <p style={{ color: 'green' }}>{successMessage}</p>}
      {actionError && <p style={{ color: 'red' }}>{actionError}</p>}
      {loading && <p>Loading prizes...</p>}
      {error && <p style={{ color: 'red' }}>{error}</p>}
      {!loading && !error && (
        <div style={{ overflowX: 'auto' }}>
          <table style={tableStyle}>
            <thead>
              <tr>
                <th style={headerStyle}>Prize</th>
                <th style={headerStyle}>Image</th>
                <th style={headerStyle}>Active</th>
                <th style={headerStyle}>Actions</th>
              </tr>
            </thead>
            <tbody>
              {gifts.map((gift, index) => (
                <tr key={gift.id} style={{ backgroundColor: index % 2 === 0 ? '#ffffff' : '#f8fafc' }}>
                  <td style={cellStyle}>{gift.name}</td>
                  <td style={cellStyle}>
                    {gift.imageUrl ? (
                      <div>
                        <div style={{ marginBottom: 6 }}>
                          <img
                            src={normalizeImageUrl(gift.imageUrl)}
                            alt={gift.name}
                            style={{ width: 48, height: 48, objectFit: 'cover', borderRadius: 6, border: '1px solid #ddd' }}
                          />
                        </div>
                        <a href={normalizeImageUrl(gift.imageUrl)} target="_blank" rel="noopener noreferrer">
                          Open
                        </a>
                      </div>
                    ) : (
                      'None'
                    )}
                  </td>
                  <td style={cellStyle}>{gift.isActive ? 'Yes' : 'No'}</td>
                  <td style={cellStyle}>
                    <button onClick={() => handleEdit(gift)} style={{ ...buttonStyle, marginRight: 8 }}>
                      Edit
                    </button>
                    <button onClick={() => handleDelete(gift.id)} style={buttonStyle}>
                      Delete
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
      {showForm && (
        <div style={{ marginTop: 24, maxWidth: 640, background: '#ffffff', border: '1px solid #e5e7eb', borderRadius: 8, padding: 16 }}>
          <h3 style={{ marginTop: 0 }}>{editingId ? 'Edit Prize' : 'Add Prize'}</h3>
          <div style={{ marginBottom: 8 }}>
            <label style={{ display: 'block', marginBottom: 4 }}>Prize Name</label>
            <input
              type="text"
              value={workingGift.name}
              onChange={(e) => setWorkingGift({ ...workingGift, name: e.target.value })}
              style={inputStyle}
            />
          </div>
          <div style={{ marginBottom: 8 }}>
            <label style={{ display: 'block', marginBottom: 4 }}>Prize Image</label>
            <input
              ref={fileInputRef}
              type="file"
              accept="image/jpeg,image/png,image/gif,image/webp"
              onChange={handleFileUpload}
              disabled={uploadingImage}
              style={{ width: '100%', padding: 8 }}
            />
            <div style={{ marginTop: 4, fontSize: 12, color: '#555' }}>
              Upload a JPEG, PNG, GIF, or WebP image (max 5MB). Recommended dimensions: at least 320×320 px, square or near-square.
              This displays best in the Flutter prize grid and helps keep six gifts visible comfortably.
            </div>
          </div>
          {workingGift.imageUrl.trim() && (
            <div style={{ marginBottom: 12 }}>
              <div style={{ marginBottom: 4, fontSize: 12, color: '#555' }}>Preview</div>
              <img
                src={normalizeImageUrl(workingGift.imageUrl.trim())}
                alt="Gift preview"
                style={{ width: 150, height: 150, objectFit: 'cover', borderRadius: 8, border: '1px solid #ddd' }}
                onError={(e) => {
                  e.currentTarget.style.display = 'none';
                }}
              />
              {editingId && (
                <div style={{ marginTop: 8 }}>
                  <button
                    type="button"
                    onClick={async () => {
                      const confirmDelete = window.confirm('Remove the uploaded image for this gift?');
                      if (!confirmDelete) {
                        return;
                      }
                      setActionError(null);
                      setSuccessMessage(null);
                      try {
                        await post(`/api/admin-lists/gifts/${editingId}/remove-image`, {});
                        setWorkingGift({ ...workingGift, imageUrl: '' });
                        setSuccessMessage('Image removed successfully.');
                      } catch (err) {
                        console.error(err);
                        setActionError('Unable to remove image.');
                      }
                    }}
                    style={{ background: '#f87171', color: '#fff', border: 'none', padding: '8px 12px', borderRadius: 4, cursor: 'pointer' }}
                  >
                    Clear image
                  </button>
                </div>
              )}
            </div>
          )}
          <div style={{ marginBottom: 12 }}>
            <label style={{ display: 'inline-flex', alignItems: 'center' }}>
              <input
                type="checkbox"
                checked={workingGift.isActive}
                onChange={(e) => setWorkingGift({ ...workingGift, isActive: e.target.checked })}
                style={{ marginRight: 8 }}
              />
              Active
            </label>
          </div>
          <button onClick={handleSubmit} disabled={uploadingImage} style={{ ...buttonStyle, marginRight: 8 }}>
            {uploadingImage ? 'Uploading...' : 'Save'}
          </button>
          <button onClick={handleCancel} style={buttonStyle}>
            Cancel
          </button>
        </div>
      )}
    </div>
  );
};

export default PrizeList;
